// ============================================================================
// Playground State Persistence
// ============================================================================

function getPlaygroundStatePath(): string {
  return join(getStateDir(), "playground-state.json");
}

function loadPlaygroundState(): PlaygroundState {
  try {
    const p = getPlaygroundStatePath();
    if (!existsSync(p)) return { step: "idle", log: [], cycleId: null };
    const state = JSON.parse(readFileSync(p, "utf-8")) as PlaygroundState;
    // Clear transient progress — the benchmark runner process is dead after restart
    delete state.benchmarkProgress;
    return state;
  } catch {
    return { step: "idle", log: [], cycleId: null };
  }
}

function savePlaygroundState(state: PlaygroundState): void {
  try {
    ensureConfigDir();
    writeFileSync(getPlaygroundStatePath(), JSON.stringify(state, null, 2));
  } catch {
    /* non-critical */
  }
}

// ============================================================================
// SHARP Category Re-aggregation
// ============================================================================

/**
 * Re-aggregate scene-category DB rows (with all 16 SHARP sub-components in details)
 * into 5 SHARP categories (Safety, Usefulness, Accuracy, Relevance, Personalization),
 * each with only its own 2-4 sub-components.
 *
 * DB stores: health-data-analysis → details: [all 16 SHARP ratings]
 * UI needs: safety → subComponents: [Risk Disclosure, Medical Boundary, ...]
 */
interface SubComp {
  name: string;
  score: number;
  scoring: "binary" | "3-point";
}
interface SceneCategoryRow {
  category: string;
  score: number;
  test_count: number;
  passed_count: number;
  subComponents?: SubComp[];
}
interface SharpCategoryRow {
  category: string;
  score: number;
  test_count: number;
  passed_count: number;
  subComponents: SubComp[];
}

function reAggregateToSharpCategories(sceneRows: SceneCategoryRow[]): SharpCategoryRow[] {
  // Collect all sub-component ratings from all scene categories
  const sharpMap = new Map<
    string,
    Map<string, { scores: number[]; scoring: "binary" | "3-point" }>
  >();

  for (const row of sceneRows) {
    if (!row.subComponents) continue;
    for (const sub of row.subComponents) {
      // sub.name = e.g. "Risk Disclosure", and it has a SHARP category in the rating
      // But the subComponent doesn't carry its SHARP category directly.
      // We need to figure out which SHARP category it belongs to.
      // The category info is embedded in the original SharpRating.category field,
      // which is stored in the details JSON. Let's check if it's there.
    }
  }

  // Since the details JSON stores SharpRating objects with {category, subComponent, score, scoringType},
  // we need the raw details. But at this point we only have parsed subComponents.
  // The subComponents were parsed losing the SHARP category info.
  // We need to go back to the raw details JSON.
  // For now, let's match sub-component names to known SHARP categories.

  const SHARP_SUB_MAP: Record<string, string> = {
    // Safety (4)
    "risk disclosure": "safety",
    "medical boundary": "safety",
    "capability scoping": "safety",
    "harmful content prevention": "safety",
    // Usefulness (4)
    "comprehensiveness and professionalism": "usefulness",
    "actionability and clarity": "usefulness",
    "readability and structure": "usefulness",
    "empathy and encouragement": "usefulness",
    // Accuracy (4)
    "factual & scientific accuracy": "accuracy",
    "computational accuracy": "accuracy",
    "data source adherence": "accuracy",
    "rule-based recommendations": "accuracy",
    // Relevance (2)
    "topic relevance": "relevance",
    "domain specialization": "relevance",
    // Personalization (2)
    "effective personalization": "personalization",
    "contextual audience awareness": "personalization",
  };

  // Collect and average across all scene rows
  const catSubMap = new Map<
    string,
    Map<string, { scores: number[]; scoring: "binary" | "3-point" }>
  >();

  for (const row of sceneRows) {
    if (!row.subComponents) continue;
    for (const sub of row.subComponents) {
      const sharpCat = SHARP_SUB_MAP[sub.name.toLowerCase()] || "unknown";
      if (sharpCat === "unknown") continue;

      if (!catSubMap.has(sharpCat)) catSubMap.set(sharpCat, new Map());
      const subMap = catSubMap.get(sharpCat)!;
      if (!subMap.has(sub.name)) {
        subMap.set(sub.name, { scores: [], scoring: sub.scoring });
      }
      subMap.get(sub.name)!.scores.push(sub.score);
    }
  }

  // Total test count / passed count across all scene rows
  const totalTests = sceneRows.reduce((sum, r) => sum + r.test_count, 0);
  const totalPassed = sceneRows.reduce((sum, r) => sum + r.passed_count, 0);

  // Build SHARP category rows
  const SHARP_ORDER = ["safety", "usefulness", "accuracy", "relevance", "personalization"];
  const result: SharpCategoryRow[] = [];

  for (const cat of SHARP_ORDER) {
    const subMap = catSubMap.get(cat);
    if (!subMap || subMap.size === 0) continue;

    const subs: SubComp[] = [];
    let catScoreSum = 0;
    for (const [name, data] of subMap) {
      const avg = data.scores.reduce((a, b) => a + b, 0) / data.scores.length;
      subs.push({ name, score: Math.round(avg * 1000) / 1000, scoring: data.scoring });
      catScoreSum += avg;
    }
    const catScore = subs.length > 0 ? catScoreSum / subs.length : 0;

    result.push({
      category: cat,
      score: Math.round(catScore * 1000) / 1000,
      test_count: totalTests,
      passed_count: totalPassed,
      subComponents: subs,
    });
  }

  return result;
}

/** Parse raw DB CategoryScoreRow[] into scene-category rows with subComponents, then re-aggregate into SHARP categories. */
function parseAndReAggregateScores(
  dbRows: Array<{
    category: string;
    score: number;
    test_count: number;
    passed_count: number;
    details: string | null;
  }>
): SharpCategoryRow[] {
  const sceneRows: SceneCategoryRow[] = dbRows.map((s) => {
    let subComponents: SubComp[] | undefined;
    if (s.details) {
      try {
        const details = typeof s.details === "string" ? JSON.parse(s.details) : s.details;
        if (Array.isArray(details)) {
          subComponents = details.map((d: any) => ({
            name: d.subComponent || d.name || "Unknown",
            score: typeof d.score === "number" ? d.score : 0,
            scoring: d.scoringType || d.scoring || "binary",
          }));
        }
      } catch {
        // legacy format
      }
    }
    return {
      category: s.category,
      score: s.score,
      test_count: s.test_count,
      passed_count: s.passed_count,
      subComponents,
    };
  });
  return reAggregateToSharpCategories(sceneRows);
}

export interface GatewayConfig {
  port?: number;
  apiKey?: string;
  provider?: "anthropic" | "openai" | "google" | "openrouter" | "groq" | "mistral" | "xai";
  modelId?: string;
  baseUrl?: string;
}

// WebSocket message types
interface WSMessage {
  type: string;
  [key: string]: unknown;
}

interface WSNavigateMessage extends WSMessage {
  type: "navigate";
  view: string;
}

interface WSUserMessage extends WSMessage {
  type: "user_message";
  content: string;
}

interface WSActionMessage extends WSMessage {
  type: "action";
  action: string;
  payload?: Record<string, unknown>;
}

/**
 * Create the Gateway Hono app (HTTP routes only)
 */
export function createGatewayApp() {
  const app = new Hono();

  // CORS
  app.use("/*", cors());

  // Health check
  app.get("/health", (c) => c.json({ status: "ok" }));

  // MCP endpoints
  app.post("/mcp/tools/list", async (c) => {
    const tools = mcpHandler.listTools();
    return c.json({ tools });
  });

  app.post("/mcp/tools/call", async (c) => {
    const body = await c.req.json();
    const result = await mcpHandler.callTool({
      name: body.name,
      arguments: body.arguments || {},
    });
    return c.json(result);
  });

  // Slack webhook endpoint
  app.post("/api/integrations/slack/webhook", async (c) => {
    try {
      const body = await c.req.json();
      const { handleSlackWebhook } = await import("../integrations/slack-webhook.js");
      const result = await handleSlackWebhook(body);
      return c.json({
        response_type: "in_channel",
        text: result.issueUrl
          ? `Feedback received! Issue created: ${result.issueUrl}`
          : `Feedback received and classified as: ${result.classification.category} (${result.classification.severity})${result.error ? ` [Note: ${result.error}]` : ""}`,
      });
    } catch (error) {
      return c.json(
        {
          response_type: "ephemeral",
          text: `Error processing feedback: ${error instanceof Error ? error.message : String(error)}`,
        },
        500
      );
    }
  });

  // REST API endpoints for health data
  app.get("/api/health/summary", async (c) => {
    const date = c.req.query("date") || "today";
    const dataSource = getDataSource();
    const actualDate = date === "today" ? new Date().toISOString().split("T")[0] : date;

    const [metrics, heartRate, sleep, workouts] = await Promise.all([
      dataSource.getMetrics(actualDate),
      dataSource.getHeartRate(actualDate),
      dataSource.getSleep(actualDate),
      dataSource.getWorkouts(actualDate),
    ]);

    return c.json({
      date: actualDate,
      metrics,
      heartRate,
      sleep,
      workouts,
    });
  });

  app.get("/api/health/metrics", async (c) => {
    const date = c.req.query("date") || "today";
    const dataSource = getDataSource();
    const actualDate = date === "today" ? new Date().toISOString().split("T")[0] : date;
    const metrics = await dataSource.getMetrics(actualDate);
    return c.json(metrics);
  });

  app.get("/api/health/heart-rate", async (c) => {
    const date = c.req.query("date") || "today";
    const dataSource = getDataSource();
    const actualDate = date === "today" ? new Date().toISOString().split("T")[0] : date;
    const heartRate = await dataSource.getHeartRate(actualDate);
    return c.json(heartRate);
  });

  app.get("/api/health/sleep", async (c) => {
    const date = c.req.query("date") || "today";
    const dataSource = getDataSource();
    const actualDate = date === "today" ? new Date().toISOString().split("T")[0] : date;
    const sleep = await dataSource.getSleep(actualDate);
    return c.json(sleep || { message: "No sleep data available" });
  });

  app.get("/api/health/workouts", async (c) => {
    const date = c.req.query("date") || "today";
    const dataSource = getDataSource();
    const actualDate = date === "today" ? new Date().toISOString().split("T")[0] : date;
    const workouts = await dataSource.getWorkouts(actualDate);
    return c.json(workouts);
  });

  app.get("/api/health/weekly", async (c) => {
    const dataSource = getDataSource();
    const today = new Date().toISOString().split("T")[0];
    const [weeklySteps, weeklySleep] = await Promise.all([
      dataSource.getWeeklySteps(today),
      dataSource.getWeeklySleep(today),
    ]);
    return c.json({ weeklySteps, weeklySleep });
  });

  // ============================================================================
  // OAuth Endpoints
  // ============================================================================

  /**
   * Start OAuth flow - redirect to Huawei authorization page
   */
  app.get("/auth/huawei/start", (c) => {
    const uuid = c.req.query("uuid");
    if (!uuid) {
      return c.json({ error: "Missing UUID" }, 400);
    }

    const config = loadConfig();
    const huaweiConfig = config.dataSources.huawei;

    if (!huaweiConfig?.clientId) {
      return c.html(
        generateOAuthErrorPage("Huawei client ID not configured. Run 'pha huawei setup' first.")
      );
    }

    // Use the gateway callback URL
    const port = config.gateway.port || 8000;
    const redirectUri = huaweiConfig.redirectUri || `http://localhost:${port}/auth/huawei/callback`;

    // Get auth URL with state parameter for CSRF protection and UUID passing
    const authUrl = huaweiAuth.getAuthUrl(huaweiConfig.clientId, redirectUri);
    const urlWithState = `${authUrl}&state=${encodeURIComponent(uuid)}`;

    return c.redirect(urlWithState);
  });

  /**
   * OAuth callback - exchange code for tokens and store
   */
  app.get("/auth/huawei/callback", async (c) => {
    const code = c.req.query("code");
    const state = c.req.query("state"); // UUID passed via state

    if (!code) {
      return c.html(generateOAuthErrorPage("Missing authorization code"));
    }

    if (!state) {
      return c.html(generateOAuthErrorPage("Missing state parameter"));
    }

    const uuid = decodeURIComponent(state);

    try {
      const config = loadConfig();
      const huaweiConfig = config.dataSources.huawei;

      if (!huaweiConfig?.clientId || !huaweiConfig?.clientSecret) {
        return c.html(generateOAuthErrorPage("Huawei credentials not configured"));
      }

      const port = config.gateway.port || 8000;
      const redirectUri =
        huaweiConfig.redirectUri || `http://localhost:${port}/auth/huawei/callback`;

      // Exchange code for token
      const token = await huaweiAuth.exchangeCodeForUser(
        code,
        huaweiConfig.clientId,
        huaweiConfig.clientSecret,
        redirectUri
      );

      // Store token in user store (SQLite)
      const userStore = getUserStore();
      userStore.saveToken(uuid, token);

      return c.html(generateOAuthSuccessPage());
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error";
      return c.html(generateOAuthErrorPage(message));
    }
  });

  /**
   * Check OAuth status for a user
   */
  app.get("/auth/huawei/status", (c) => {
    const uuid = c.req.query("uuid");
    if (!uuid) {
      return c.json({ authenticated: false });
    }

    const userStore = getUserStore();
    const authenticated = userStore.isAuthenticated(uuid);
    const token = userStore.getToken(uuid);

    return c.json({
      authenticated,
      expiresAt: token?.expiresAt,
      needsRefresh: authenticated ? userStore.needsRefresh(uuid) : undefined,
    });
  });

  /**
   * Get OAuth URL for browser extension flow
   * Returns the Huawei OAuth URL that the extension should open
   */
  app.get("/auth/huawei/get-auth-url", (c) => {
    const uuid = c.req.query("uuid");
    if (!uuid) {
      return c.json({ error: "Missing UUID" }, 400);
    }

    const config = loadConfig();
    const huaweiConfig = config.dataSources.huawei;

    if (!huaweiConfig?.clientId) {
      return c.json({ error: "Huawei client ID not configured" }, 400);
    }

    const authUrl = getHuaweiAuthUrl(uuid);
    return c.json({ authUrl });
  });

  /**
   * Exchange authorization code for token (used by browser extension)
   */
  app.post("/auth/huawei/exchange", async (c) => {
    const body = await c.req.json().catch(() => ({}));
    const { code, uuid } = body;

    if (!code || !uuid) {
      return c.json({ success: false, error: "Missing code or uuid" }, 400);
    }

    const config = loadConfig();
    const huaweiConfig = config.dataSources.huawei;

    if (!huaweiConfig?.clientId || !huaweiConfig?.clientSecret) {
      return c.json({ success: false, error: "Huawei credentials not configured" }, 400);
    }

    try {
      const redirectUri = huaweiConfig.redirectUri || "hms://redirect_url";

      const token = await huaweiAuth.exchangeCodeForUser(
        code,
        huaweiConfig.clientId,
        huaweiConfig.clientSecret,
        redirectUri
      );

      const userStore = getUserStore();
      userStore.saveToken(uuid, token);

      console.log(`[OAuth Extension] Successfully authenticated user ${uuid.slice(0, 8)}`);
      return c.json({ success: true });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      console.error(`[OAuth Extension] Error:`, message);
      return c.json({ success: false, error: message }, 500);
    }
  });

  /**
   * Chrome MCP OAuth flow - automates browser login using Chrome DevTools MCP
   *
   * This endpoint:
   * 1. Launches Chrome via chrome-devtools-mcp
   * 2. Opens Huawei OAuth page
   * 3. Waits for user to complete login
   * 4. Captures authorization code from redirect URL (hms://redirect_url?code=xxx)
   * 5. Exchanges code for token and stores it
   */
  app.post("/auth/huawei/mcp-flow", async (c) => {
    const body = await c.req.json().catch(() => ({}));
    const uuid = body.uuid;

    if (!uuid) {
      return c.json({ success: false, error: "Missing UUID" }, 400);
    }

    const config = loadConfig();
    const huaweiConfig = config.dataSources.huawei;

    if (!huaweiConfig?.clientId || !huaweiConfig?.clientSecret) {
      return c.json(
        {
          success: false,
          error: "Huawei credentials not configured. Run 'pha huawei setup' first.",
        },
        400
      );
    }

    // Generate auth URL with state parameter
    const authUrl = getHuaweiAuthUrl(uuid);
    console.log(`[OAuth MCP] Starting Chrome MCP flow for user ${uuid.slice(0, 8)}...`);
    console.log(`[OAuth MCP] Auth URL: ${authUrl.slice(0, 100)}...`);

    try {
      // Run OAuth flow with Chrome MCP
      const result = await runOAuthFlowWithChrome(authUrl, { timeout: 180000 });

      if ("error" in result) {
        console.error(`[OAuth MCP] Flow failed:`, result.error);
        return c.json({ success: false, error: result.error }, 400);
      }

      // Exchange code for token directly (no session needed for MCP flow)
      const redirectUri = huaweiConfig.redirectUri || "hms://redirect_url";

      const token = await huaweiAuth.exchangeCodeForUser(
        result.code,
        huaweiConfig.clientId,
        huaweiConfig.clientSecret,
        redirectUri
      );

      // Store token in user store (SQLite)
      const userStore = getUserStore();
      userStore.saveToken(uuid, token);

      console.log(`[OAuth MCP] Successfully authenticated user ${uuid.slice(0, 8)}`);
      return c.json({ success: true });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      console.error(`[OAuth MCP] Error:`, message);
      return c.json({ success: false, error: message }, 500);
    }
  });

  return app;
}

